// Householder QR on A (also updates b = Q^T b and builds Q^T)
// Inputs: A (n x n), b (n), epsilon (singularity threshold)
// Outputs: A becomes R; b becomes Q^T b; Qt holds Q^T
Qt = I_n;
for (int r = 0; r < n - 1; r++) {
    // ---- build the reflection P_r: u and beta ----
    double sigma = 0;
    for (int i = r; i < n; i++) sigma += A[i][r] * A[i][r];
    if (sigma <= epsilon) break;          // A is singular at this pivot
    double k = sqrt(sigma);
    if (A[r][r] > 0) k = -k;              // sign rule: sign(k) = -sign(a_rr)
    double beta = sigma - k * A[r][r];
    double u[n];
    for (int i = 0;   i < r; i++) u[i] = 0;
    u[r] = A[r][r] - k;
    for (int i = r + 1; i < n; i++) u[i] = A[i][r];

    // ---- apply P_r to columns j >= r+1 of A ----
    for (int j = r + 1; j < n; j++) {
        double g = 0;
        for (int i = r; i < n; i++) g += u[i] * A[i][j];
        g /= beta;
        for (int i = r; i < n; i++) A[i][j] -= g * u[i];
    }
    // ---- rewrite column r of A explicitly ----
    A[r][r] = k;
    for (int i = r + 1; i < n; i++) A[i][r] = 0;

    // ---- apply P_r to b and Qt ----
    double g = 0;
    for (int i = r; i < n; i++) g += u[i] * b[i];
    g /= beta;
    for (int i = r; i < n; i++) b[i] -= g * u[i];

    for (int j = 0; j < n; j++) {
        double gq = 0;
        for (int i = r; i < n; i++) gq += u[i] * Qt[i][j];
        gq /= beta;
        for (int i = r; i < n; i++) Qt[i][j] -= gq * u[i];
    }
}
// On exit: A = R (upper-triangular), b = Q^T b, Qt = Q^T.

// Givens QR: applies rotations in planes (p, q) to kill entries one at a time
for (int r = 0; r < n - 1; r++) {
    for (int q = r + 1; q < n; q++) {
        // Rotation in plane (r, q) to zero entry A[q][r]
        double apr = A[r][r], aqr = A[q][r];
        double rho = hypot(apr, aqr);           // sqrt(apr^2 + aqr^2), safer
        if (rho == 0.0) continue;                // already zero, skip
        double c = apr / rho, s = aqr / rho;

        // Update rows p = r and q: B_p = c*A_p + s*A_q, B_q = -s*A_p + c*A_q
        for (int j = r; j < n; j++) {
            double ar = A[r][j], aq = A[q][j];
            A[r][j] =  c * ar + s * aq;
            A[q][j] = -s * ar + c * aq;
        }
        // Same update on the RHS b (and cumulatively on Q^T)
        double br = b[r], bq = b[q];
        b[r] =  c * br + s * bq;
        b[q] = -s * br + c * bq;
    }
}
// On exit: A = R, b = Q^T b.

// Classical Gram-Schmidt: A (n columns a_1..a_n) -> Q, R
for (int k = 0; k < n; k++) {
    for (int i = 0; i < k; i++) {
        R[i][k] = 0;                            // r_ik = q_i^T a_k
        for (int j = 0; j < n; j++) R[i][k] += Q[j][i] * A[j][k];
    }
    double qt[n];                               // tilde q_k
    for (int j = 0; j < n; j++) {
        qt[j] = A[j][k];
        for (int i = 0; i < k; i++) qt[j] -= R[i][k] * Q[j][i];
    }
    R[k][k] = 0;
    for (int j = 0; j < n; j++) R[k][k] += qt[j] * qt[j];
    R[k][k] = sqrt(R[k][k]);
    for (int j = 0; j < n; j++) Q[j][k] = qt[j] / R[k][k];
}

// Modified Gram-Schmidt: subtract projections one at a time
for (int k = 0; k < n; k++) {
    double v[n];
    for (int j = 0; j < n; j++) v[j] = A[j][k];
    for (int i = 0; i < k; i++) {
        R[i][k] = 0;                            // r_ik = q_i^T v (current v!)
        for (int j = 0; j < n; j++) R[i][k] += Q[j][i] * v[j];
        for (int j = 0; j < n; j++) v[j] -= R[i][k] * Q[j][i];   // update v
    }
    R[k][k] = 0;
    for (int j = 0; j < n; j++) R[k][k] += v[j] * v[j];
    R[k][k] = sqrt(R[k][k]);
    for (int j = 0; j < n; j++) Q[j][k] = v[j] / R[k][k];
}
